DROP TABLE IF EXISTS `box_openings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `box_openings` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `user_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `box_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `box_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `box_pokeball_image` varchar(512) COLLATE utf8mb4_unicode_ci NOT NULL,
  `resource_type` enum('POKEMON','ITEM','MACHINE') COLLATE utf8mb4_unicode_ci NOT NULL,
  `resource_id` int NOT NULL,
  `resource_name` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `drop_rate` double NOT NULL,
  `details` json DEFAULT NULL,
  `opened_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  `updated_at` datetime(3) NOT NULL,
  `is_shiny` tinyint(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `box_openings_user_id_opened_at_idx` (`user_id`,`opened_at`),
  KEY `box_openings_box_id_idx` (`box_id`),
  CONSTRAINT `box_openings_box_id_fkey` FOREIGN KEY (`box_id`) REFERENCES `boxes` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `box_openings_user_id_fkey` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

